var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"말도 없이 집까지 찾아오다니……. 같이 일했던 사이끼리 조금 심하시네요.","JPN":"なんの連絡もなく家まで来て……一緒に働いた間柄にしてもあんまりですね。","ENG":"And you come to my house without letting me know... We've been working together, but isn't it too much?","TWN":"竟然沒事先說一聲跑來我家……同事之間是不是有點越界？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"이상하군. 우리 방식은 자네가 가장 잘 알고 있을 텐데.","JPN":"おかしいな。私たちのやり方は君が一番よく知っているはずだ。","ENG":"Strange. You of all people should be familiar with our ways.","TWN":"真是奇怪，我們的做事方式，你應該是最清楚的吧？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"어머니에게 숨겼던 직장이 들통나서 그런 건가?","JPN":"母親に職場がバレるからか？","ENG":"Are you worried your mother will discover what line of work you’re in? Is that it?","TWN":"還是因為被媽媽發現你的工作，才會有這種反應？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"안 그러신 줄 알았는데 뒤끝이 심하시네요.","JPN":"見かけによらずしつこいですね。","ENG":"I didn’t think you were like this. Aren’t you taking things too far?","TWN":"我以為你們不至於如此，沒想到這麼愛記仇。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"아직도 제가 어머니 때문에 일을 망쳤다고 의심하는 건가요?","JPN":"私が母のせいで仕事をダメにしたって、まだ疑ってるんですか？","ENG":"You think I messed up during the operation because of my concern for my mother?","TWN":"你們還在懷疑我是因為媽媽的關係，才把事情搞砸的嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>파레마 건은 불운한 사고였다.</color> 자네가 제출한 시말서는 읽어 봤어.","JPN":"<color=#ffd34c>パレマの件は不運な事故だった。</color>君が提出した始末書は読んであるんだ。","ENG":"<color=#ffd34c>The Parema incident was an unfortunate accident.</color> I read your report.","TWN":"<color=#ffd34c>波雷馬的事是倒楣的意外。</color>我有看過你提出的報告。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"하지만 왜 하필 그 때 실패했지?","JPN":"しかし、なぜよりにもよってあの時失敗したんだ？","ENG":"However, why was it that day that you failed?","TWN":"但為何偏偏在那個時候失手呢？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"출처가 불분명한 정보를 믿고 순혈지식 연대의 거점을 공격한 것도, 맨션 조사를 지원한 것도.","JPN":"出所が怪しい情報を信じて純血知識連帯の拠点を攻撃したことも、マンションの調査を支援したことも。","ENG":"You attacked the Pureblood Knowledge Regiment’s base by trusting information from an untrustworthy source, and you volunteered for the Mansion investigation.","TWN":"之前根據連來路不明的情報，攻擊純血知識年代的據點，還有支援調查曼森，"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"하나같이 얼토당토 않은 임무였고 상정하지 않은 사태가 잔뜩 터졌어.","JPN":"すべてがでたらめな任務で、想定していなかった事態がたくさん起こった。","ENG":"The mission was an absolute mess. So many unexpected occurrences.","TWN":"都是些高難度的任務，甚至還發生許多插曲。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그런데 하필이면 멍청한 자크가 자네 어머니에 대해 지껄인 날…… 일이 틀어졌지.","JPN":"そしてよりによってあの間抜けなジャックが君の母親についてしゃべった日……計画が失敗した。","ENG":"Even so, from the moment that fool, Jacques, mentioned your mother... Things went horribly wrong.","TWN":"為什麼偏偏在愚蠢的札克提起你媽媽的這一天……搞砸任務呢？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"조사는 대기 처분을 받기 전에도 원없이 했잖아요?","JPN":"待機処分を食らう前にも調査ならさんざんしたでしょう？","ENG":"You performed an investigation even before I was placed on standby, didn’t you?","TWN":"有關於我的調查，不是在停職處分前就已經調查完畢嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"어머니는 총 든 사람들을 무서워하세요. 어서 본론으로 들어가죠.","JPN":"母は銃を持った人を怖がるんです。すぐ本題に入ってください。","ENG":"Look. My mother gets frightened when people with guns are around. Let’s get straight to the point.","TWN":"我媽會害怕拿槍的人，有什麼事就快說吧！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자네가 해 줘야 할 일이 생겼어.","JPN":"君にやって貰わなけらばならないことがある。","ENG":"There’s something I need you to do for me.","TWN":"有件事需要你出馬。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"저는 지금 생활도 꽤 만족하고 있어요. 세 사람이 지내기에 배급이 부족한 점만 제외하면요.","JPN":"私は今の生活にも結構満足してます。三人で過ごすのに配給が足りないのを除けばですけど。","ENG":"Aside from lacking supplies for three people, I’m quite satisfied with my life right now.","TWN":"雖然三個人光靠配給生活有點辛苦，但我對現在的生活挺滿意的。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"제대로 일하지 않는 사람이 둘이나 있는데 배급품은 세 사람 몫으로 나가고 있지.","JPN":"しっかり働いていない者が二人もいるが、配給は三人分が出ているな。","ENG":"Only one person working in a household of three, and still you’re getting supplies for three.","TWN":"有兩個人沒在工作，配給品卻要養活三個人，當然辛苦。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"배를 곪으면서도 자네 친구가 여기 붙어 있을까? 어머니의 여생을 생각해.","JPN":"飢えながらも君の友人がここに残るだろうか？　母親の余生を考えろ。","ENG":"And if you all continue to go hungry, do you think your friend will still stick around? Please, think about your mother’s life.","TWN":"你朋友就算餓肚子也會留在這裡嗎？再說你也要替媽媽的將來想一想。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"……보안국에 인재가 그렇게 없나요?","JPN":"……保安局はそんなに人材が足りないのですか？","ENG":"...Is the National Security so desperate for people?","TWN":"……安全局是沒人才了嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"유능한 인재는 항상 부족하지. 덕분에 자네랑 내가 총살형을 안 당한 거야.","JPN":"有能な人材は常に足りない。おかげで君と私は銃殺刑を免れたんだ。","ENG":"There is always a shortage of talented people. And it is because of that, that we aren’t being executed.","TWN":"優秀的人才本來就難尋，多虧有你，我們才不用遭到槍決呢。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"}}}}]`);export{e as default};